import{_ as a,o as i,c as t,ag as n}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"NOM","description":"","frontmatter":{},"headers":[],"relativePath":"en/standards/organizations/nom.md","filePath":"en/standards/organizations/nom.md"}'),r={name:"en/standards/organizations/nom.md"};function o(l,e,s,d,c,p){return i(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="nom" tabindex="-1">NOM <a class="header-anchor" href="#nom" aria-label="Permalink to &quot;NOM&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Normas Oficiales Mexicanas (NOM) are mandatory standards issued by the Mexican government that define requirements for safety, performance, labeling, and installation of products and systems.</p><p>They establish the legal framework for compliance in Mexico and are enforced by regulatory authorities.</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>NOM standards are used to:</p><ul><li>Ensure safety of people and infrastructure</li><li>Define mandatory technical and installation requirements</li><li>Regulate products entering and used within Mexico</li><li>Support inspection, approval, and legal compliance</li><li>Align national requirements with international practices when applicable</li></ul><p>They are required for equipment and systems to be legally installed and operated in Mexico.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>NOM standards define:</p><ul><li>Technical requirements and performance criteria</li><li>Safety rules and protection measures</li><li>Testing and verification procedures</li><li>Labeling and documentation requirements</li></ul><p>Compliance is typically verified through:</p><ul><li>Accredited testing laboratories</li><li>Certification bodies authorized in Mexico</li><li>Official markings and documentation</li></ul><p>Unlike voluntary standards, NOM compliance is mandatory for applicable products and installations.</p><h2 id="applications" tabindex="-1">Applications <a class="header-anchor" href="#applications" aria-label="Permalink to &quot;Applications&quot;">​</a></h2><p>NOM standards apply to:</p><ul><li>Electrical equipment and installations</li><li>Control panels and industrial systems</li><li>Consumer and industrial products entering the Mexican market</li><li>Machinery and safety-related systems</li></ul><p>They are required in:</p><ul><li>Industrial facilities in Mexico</li><li>Imported equipment and machinery</li><li>Projects subject to inspection by local authorities</li></ul><h2 id="key-considerations" tabindex="-1">Key Considerations <a class="header-anchor" href="#key-considerations" aria-label="Permalink to &quot;Key Considerations&quot;">​</a></h2><ul><li>NOM standards are legally mandatory, not optional</li><li>Certification is often required for product approval and importation</li><li>NOM standards may reference or align with international standards</li><li>Documentation and labeling must meet specific national requirements</li><li>Non-compliance can result in rejection, fines, or operational restrictions</li></ul><h2 id="practical-notes" tabindex="-1">Practical Notes <a class="header-anchor" href="#practical-notes" aria-label="Permalink to &quot;Practical Notes&quot;">​</a></h2><ul><li>Always verify which NOM standards apply to the project or equipment</li><li>Ensure certification is completed before installation or import</li><li>Do not assume international compliance automatically satisfies NOM requirements</li><li>Work with certified laboratories or approved bodies when required</li><li>Missing NOM compliance is a common cause of project delays in Mexico</li></ul>',23)])])}const h=a(r,[["render",o]]);export{m as __pageData,h as default};
